SELECT COUNT(template_id) AS active_templates_count
FROM email_templates
WHERE is_active = 1;

SELECT template_name
FROM email_templates
WHERE is_active = 1;

SELECT type_name, description
FROM email_types
WHERE is_transactional = 1;

SELECT category_name, description, created_at
FROM template_categories
ORDER BY created_at DESC;

SELECT status, total_recipients, created_at
FROM email_campaigns
ORDER BY created_at DESC;

SELECT SUM(sent_count) AS total_sent
FROM template_analytics
WHERE template_id = 0;
